props.content:
type InterventionDelta = {
  kind: "inject_context" | "modify_action" | "block" | "redirect" | "request_human" | "noop";
  program_id: string;
  activation: {
    predicate_id: string;
    facts: Record<string, unknown>;
    deterministic_hash: string;
  };
  before: unknown;
  after: unknown;
  proof: {
    preservation: number;
    necessity: number;
    evidence_refs: string[];
  };
};

type RepairReceipt = {
  status: "valid" | "repaired" | "blocked";
  original_action: unknown;
  repaired_action: unknown | null;
  rule_id: string;
  model_output_changed: false;
  structural_error_before: string[];
  structural_error_after: string[];
  evidence_refs: string[];
};

type RetrievalComparison = {
  query_id: string;
  baseline: RetrievalScore;
  topology: RetrievalScore;
  winner: "baseline" | "topology" | "tie";
  evidence_chain: string[];
  provenance_coverage: number;
  token_estimate: number;
};
